/**
 * tests/fixtures/_generate.mjs
 *
 * 最小テクスチャ (1×1 pixel) を生成するスクリプト。
 * 実行: node tests/fixtures/_generate.mjs
 *
 * 生成対象:
 *   textures/1x1.png  — 1×1 RGBA=255,0,0,255 (red)
 *   textures/1x1.jpg  — 1×1 RGB=0,255,0 (green)  ※ JFIF raw bytes
 *
 * バイナリは Node Buffer + fs.writeFileSync で書き込む (echo/printf は使わない)。
 */

import { writeFileSync, mkdirSync } from "fs";
import { dirname, join } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const texturesDir = join(__dirname, "textures");
mkdirSync(texturesDir, { recursive: true });

// -----------------------------------------------------------------------
// 1×1 PNG  (RGBA: 255, 0, 0, 255 = red)
// zlib (Node 18+ 組込み) で IDAT を deflate して正確な PNG を生成する。
// -----------------------------------------------------------------------

import { deflateSync } from "zlib";

function crc32(buf) {
  const table = new Uint32Array(256);
  for (let n = 0; n < 256; n++) {
    let c = n;
    for (let k = 0; k < 8; k++) c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
    table[n] = c;
  }
  let crc = 0xffffffff;
  for (const byte of buf) crc = table[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  return (crc ^ 0xffffffff) >>> 0;
}

function chunk(type, data) {
  const typeBytes = Buffer.from(type, "ascii");
  const len = Buffer.alloc(4);
  len.writeUInt32BE(data.length);
  const crcBuf = Buffer.concat([typeBytes, data]);
  const crcVal = Buffer.alloc(4);
  crcVal.writeUInt32BE(crc32(crcBuf));
  return Buffer.concat([len, typeBytes, data, crcVal]);
}

function makePng(r, g, b, a = 255) {
  const sig = Buffer.from([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]);

  // IHDR: 1×1, 8bit, color type 6 (RGBA)
  const ihdrData = Buffer.alloc(13);
  ihdrData.writeUInt32BE(1, 0); // width
  ihdrData.writeUInt32BE(1, 4); // height
  ihdrData[8] = 8; // bit depth
  ihdrData[9] = 6; // color type RGBA
  ihdrData[10] = 0; // compression
  ihdrData[11] = 0; // filter
  ihdrData[12] = 0; // interlace

  // Raw row: filter_byte(0) + R + G + B + A
  const raw = Buffer.from([0, r, g, b, a]);
  const compressed = deflateSync(raw);
  const idatData = Buffer.from(compressed);

  const iendData = Buffer.alloc(0);

  return Buffer.concat([
    sig,
    chunk("IHDR", ihdrData),
    chunk("IDAT", idatData),
    chunk("IEND", iendData),
  ]);
}

// 1×1 red PNG
const pngPath = join(texturesDir, "1x1.png");
writeFileSync(pngPath, makePng(255, 0, 0, 255));
console.log(`Written: ${pngPath}`);

